/************************************************************************* * The contents of this file are subject to the Openbravo Public License * Version 1.1 (the "License"), being the Mozilla Public License * Version 1.1 with a permitted attribution clause; you may not use this * file except in compliance with the License. You may obtain a copy of * the License at http://www.openbravo.com/legal/license.html * Software distributed under the License is distributed on an "AS IS" * basis, WITHOUT WARRANTY OF ANY KIND, either express or implied. See the * License for the specific language governing rights and limitations * under the License. * The Original Code is Openbravo ERP. * The Initial Developer of the Original Code is Openbravo SLU * All portions are Copyright (C) 2011-2018 Openbravo SLU * All Rights Reserved. * Contributor(s): ______________________________________. ************************************************************************/ v_success_insert CHAR(1) := 'N'; BEGIN INSERT INTO obpos_errors ( obpos_errors_id, ad_client_id, ad_org_id, isactive, created, createdby, updated, updatedby, jsoninfo, error, saveagain, deleteerror, orderstatus, typeofdata, obpos_applications_id, attempts, processing ) SELECT get_uuid(), ad_client_id, ad_org_id, isactive, created, createdby, updated, updatedby, jsondata, errorinfo, 'N', 'N', 'N', typeofdata, em_obpos_applications_id, 0, 'N' FROM c_import_entry WHERE c_import_entry_id = entry_id;
v_success_insert := 'Y'; RETURN v_success_insert;
EXCEPTION WHEN OTHERS THEN DBMS_OUTPUT.PUT_LINE( 'sspiers_insert_obposerror exception'); RAISE; RETURN SQLERRM; END SSPIERS_INSERT_OBPOSERROR
